patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..25ee4c029bfe 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1132,6 +1132,21 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
   };

   if (LHSIsSelect && RHSIsSelect && A == D) {
+    // Check for swapped operands with same condition for commutative ops:
+    // (A ? B : C) op (A ? C : B) -> (B op C) since op is commutative
+    if (I.isCommutative() && B == F && C == E) {
+      Value *V = simplifyBinOp(Opcode, B, C, FMF, Q);
+      if (!V && LHS->hasOneUse() && RHS->hasOneUse()) {
+        if (auto *NewBO = dyn_cast<BinaryOperator>(Builder.CreateBinOp(Opcode, B, C))) {
+          NewBO->copyIRFlags(&I);
+          V = NewBO;
+        }
+      }
+      if (V)
+        return V;
+    }
+
+    // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);

